import { defineConfig } from 'vitest/config'
import react from '@vitejs/plugin-react'
import { fileURLToPath, URL } from 'node:url'

async function loadTddGuardReporter() {
  const projectRoot = process.env.TDD_GUARD_PROJECT_ROOT
  if (!projectRoot) {
    return null
  }

  try {
    const dynamicImport = new Function('specifier', 'return import(specifier)') as (
      specifier: string,
    ) => Promise<{ VitestReporter?: new (root: string) => unknown }>
    const mod = await dynamicImport('tdd-guard-vitest')
    if (!mod.VitestReporter) {
      throw new Error('tdd-guard-vitest did not export VitestReporter')
    }
    return new mod.VitestReporter(projectRoot)
  } catch (error) {
    if (process.env.TDD_GUARD_REQUIRED === '1') {
      throw error
    }
    console.warn('vitest: tdd-guard-vitest not installed; continuing without TDD Guard reporter')
    return null
  }
}

export default defineConfig(async () => {
  const tddGuardReporter = await loadTddGuardReporter()

  return {
    plugins: [react()],
    resolve: {
      alias: {
        '@': fileURLToPath(new URL('./src', import.meta.url)),
      },
    },
    test: {
      environment: 'happy-dom',
      setupFiles: ['./src/test/setup.ts'],
      exclude: ['e2e/**', 'node_modules/**'],
      reporters: tddGuardReporter ? ['default', tddGuardReporter] : ['default'],
      coverage: {
        provider: 'v8',
        reporter: ['text', 'lcov'],
        include: ['src/**/*.{ts,tsx}'],
        exclude: ['src/test/**', 'src/**/*.test.{ts,tsx}', 'src/main.tsx', 'src/vite-env.d.ts'],
        thresholds: {
          lines: 80,
          functions: 80,
          branches: 80,
          statements: 80,
        },
      },
    },
  }
})

